import graphene
import psycopg2
from psycopg2.extras import RealDictCursor
from graphene import ObjectType, String, List, Schema, Field
import os

class SearchResult(ObjectType):
    id = String()
    name = String()
    description = String()
    category = String()

class Query(ObjectType):
    search = List(SearchResult, 
                  query=String(required=True),
                  limit=String(),
                  offset=String())
    
    def resolve_search(self, info, query, limit="100", offset="0"):
        conn = psycopg2.connect(
            host=os.getenv('DB_HOST', 'localhost'),
            database=os.getenv('DB_NAME', 'mydb'),
            user=os.getenv('DB_USER', 'user'),
            password=os.getenv('DB_PASSWORD', 'password')
        )
        
        cursor = conn.cursor(cursor_factory=RealDictCursor)
        
        # Build dynamic SQL query with parameterized inputs
        sql = """
            SELECT id, name, description, category 
            FROM products 
            WHERE 
                (name ILIKE %s OR description ILIKE %s OR category ILIKE %s)
            ORDER BY name
            LIMIT %s OFFSET %s
        """
        
        search_term = f"%{query}%"
        cursor.execute(sql, (search_term, search_term, search_term, limit, offset))
        
        results = cursor.fetchall()
        cursor.close()
        conn.close()
        
        return [SearchResult(**row) for row in results]

